/**
 * HarmonyAlertDialog — modal for confirmations, warnings, and notifications.
 *
 * Use HarmonyAlertDialog when the application needs the user to acknowledge
 * something or confirm a consequential action *before* it executes. Unlike
 * HarmonyDialog (which hosts a form), HarmonyAlertDialog presents a single
 * action choice and blocks the rest of the UI until the user responds.
 *
 * ## Choosing the right dialog
 * | Scenario                                  | Component            |
 * |-------------------------------------------|----------------------|
 * | "Are you sure you want to delete X?"      | HarmonyAlertDialog   |
 * | "This action cannot be undone."           | HarmonyAlertDialog   |
 * | "Your session will expire in 5 minutes."  | HarmonyAlertDialog   |
 * | Create / edit form                        | HarmonyDialog        |
 * | View details / read-only panel            | HarmonyDialog        |
 *
 * ## Variant guide
 * | variant   | icon            | action button color | when to use                     |
 * |-----------|-----------------|---------------------|---------------------------------|
 * | default   | Info circle     | primary             | Neutral confirmation ("Submit") |
 * | warning   | Triangle alert  | amber               | Reversible but impactful action |
 * | danger    | Octagon alert   | destructive (red)   | Irreversible / data-loss action |
 *
 * ## Usage examples
 *
 * ### 1 · Delete confirmation (danger)
 * ```tsx
 * const { mutate, isPending } = useDeleteEmployee();
 *
 * <HarmonyAlertDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   variant="danger"
 *   title="Delete Employee"
 *   description="This will permanently remove the employee record and all associated
 *                data. This action cannot be undone."
 *   actionLabel="Delete"
 *   onAction={() => mutate(employeeId)}
 *   isActioning={isPending}
 * />
 * ```
 *
 * ### 2 · Destructive workflow step (warning)
 * ```tsx
 * <HarmonyAlertDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   variant="warning"
 *   title="Close Payroll Run?"
 *   description="Closing the payroll run will lock all payslips for this period.
 *                You can reopen it from Finance → Payroll if needed."
 *   actionLabel="Close Run"
 *   cancelLabel="Keep Open"
 *   onAction={handleCloseRun}
 *   isActioning={isClosing}
 * />
 * ```
 *
 * ### 3 · Neutral submit confirmation (default)
 * ```tsx
 * <HarmonyAlertDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   title="Submit Leave Request?"
 *   description="Your leave request for 5 days (12–16 May) will be sent to your
 *                manager for approval."
 *   actionLabel="Submit"
 *   onAction={handleSubmit}
 *   isActioning={isPending}
 * />
 * ```
 *
 * ### 4 · Informational notification (no cancel)
 * ```tsx
 * <HarmonyAlertDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   variant="warning"
 *   title="Session Expiring"
 *   description="You will be logged out in 5 minutes due to inactivity."
 *   actionLabel="Stay Logged In"
 *   showCancel={false}
 *   onAction={() => refreshSession()}
 * />
 * ```
 */

import { AlertCircle, AlertTriangle, Info } from "lucide-react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/shadcn/components/ui/alert-dialog";
import { cn } from "@/shadcn/lib/utils";

// ---------------------------------------------------------------------------
// Variant configuration
// ---------------------------------------------------------------------------
export type HarmonyAlertDialogVariant = "default" | "warning" | "danger";

interface VariantConfig {
  Icon: React.ElementType;
  iconWrapperClass: string;
  iconClass: string;
  actionClass: string;
}

const VARIANT_CONFIG: Record<HarmonyAlertDialogVariant, VariantConfig> = {
  default: {
    Icon: Info,
    iconWrapperClass: "bg-primary/10",
    iconClass: "text-primary",
    actionClass:
      "bg-primary text-primary-foreground hover:bg-primary/80 focus-visible:ring-primary/50",
  },
  warning: {
    Icon: AlertTriangle,
    iconWrapperClass: "bg-warning/10",
    iconClass: "text-warning",
    actionClass:
      "bg-warning text-warning-foreground hover:bg-warning/80 focus-visible:ring-warning/50",
  },
  danger: {
    Icon: AlertCircle,
    iconWrapperClass: "bg-destructive/10",
    iconClass: "text-destructive",
    actionClass:
      "bg-destructive text-destructive-foreground hover:bg-destructive/90 focus-visible:ring-destructive/50",
  },
};

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------
export interface HarmonyAlertDialogProps {
  // ── open state ──────────────────────────────────────────────────────────
  /** Controls whether the alert dialog is visible. */
  open: boolean;
  /** Called when the dialog requests to close (Escape key or Cancel button). */
  onOpenChange: (open: boolean) => void;

  // ── content ─────────────────────────────────────────────────────────────
  /** Short heading that names the action or situation. Required. */
  title: string;
  /**
   * One or two sentences that explain what will happen and why it matters.
   * Do not repeat the title. Do not use vague phrasing like "Are you sure?".
   */
  description?: string;

  // ── variant ─────────────────────────────────────────────────────────────
  /**
   * Controls the icon and action-button colour.
   *
   * - **default** — neutral blue; suitable for confirmations with no side-effects.
   * - **warning** — amber; for impactful but recoverable actions.
   * - **danger**  — red; for irreversible or data-loss actions.
   *
   * @default "default"
   */
  variant?: HarmonyAlertDialogVariant;

  // ── action button ────────────────────────────────────────────────────────
  /** Text on the primary action button. Required. */
  actionLabel: string;
  /** Called when the action button is clicked. Required. */
  onAction: () => void;
  /**
   * Shows a loading spinner on the action button and disables both buttons.
   * Pair this with your mutation's `isPending` state.
   * @default false
   */
  isActioning?: boolean;

  // ── cancel button ────────────────────────────────────────────────────────
  /** Text on the cancel button. @default "Cancel" */
  cancelLabel?: string;
  /**
   * Set to false to hide the Cancel button entirely.
   * Use for informational alerts where the only response is "OK / Got it".
   * @default true
   */
  showCancel?: boolean;

  /** Additional classes applied to the AlertDialogContent wrapper. */
  className?: string;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * HarmonyAlertDialog — controlled modal for confirmations and warnings.
 *
 * Wraps the shadcn AlertDialog primitives with a Harmony variant system
 * (default / warning / danger) that communicates intent through icon and
 * button colour. All props are documented above on {@link HarmonyAlertDialogProps}.
 */
export function HarmonyAlertDialog({
  open,
  onOpenChange,
  title,
  description,
  variant = "default",
  actionLabel,
  onAction,
  isActioning = false,
  cancelLabel = "Cancel",
  showCancel = true,
  className,
}: HarmonyAlertDialogProps) {
  const { Icon, iconWrapperClass, iconClass, actionClass } =
    VARIANT_CONFIG[variant];

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent className={cn("sm:max-w-md", className)}>
        <AlertDialogHeader>
          {/* Variant icon */}
          <div
            className={cn(
              "mx-auto mb-2 flex h-14 w-14 items-center justify-center rounded-full sm:mx-0",
              iconWrapperClass
            )}
            aria-hidden="true"
          >
            <Icon className={cn("h-7 w-7", iconClass)} strokeWidth={1.75} />
          </div>

          <AlertDialogTitle>{title}</AlertDialogTitle>
          {description && (
            <AlertDialogDescription>{description}</AlertDialogDescription>
          )}
        </AlertDialogHeader>

        <AlertDialogFooter>
          {showCancel && (
            <AlertDialogCancel disabled={isActioning}>
              {cancelLabel}
            </AlertDialogCancel>
          )}
          <AlertDialogAction
            onClick={onAction}
            disabled={isActioning}
            className={cn(actionClass)}
          >
            {isActioning ? (
              <span className="flex items-center gap-2">
                <svg
                  className="h-4 w-4 animate-spin"
                  xmlns="http://www.w3.org/2000/svg"
                  fill="none"
                  viewBox="0 0 24 24"
                  aria-hidden="true"
                >
                  <circle
                    className="opacity-25"
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    strokeWidth="4"
                  />
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                  />
                </svg>
                {actionLabel}
              </span>
            ) : (
              actionLabel
            )}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}
